#!/usr/bin/env bash
# Pre-push gate. Mirrors the steps both workflows run in CI (.github/
# workflows/{ci,release}.yml) so failures show up locally instead of
# breaking the deploy. Build must run BEFORE typecheck/test — downstream
# workspace packages import from @released/core whose .d.ts files are
# only generated by the build.
#
# Lint runs LAST: build/typecheck/test tell you whether the code is
# broken; lint is a fast nag layer for style and a11y. Putting it last
# means a broken build doesn't hide behind lint noise.
#
# Skip with `git push --no-verify` when intentionally pushing WIP.
set -euo pipefail

# Skip in CI — the workflow already runs build/typecheck/test/lint as
# explicit steps, and the Changesets action's force-push to
# changeset-release/main triggers this via the pre-push hook,
# duplicating work and risking environmental mismatches.
if [ -n "${CI:-}" ]; then
  exit 0
fi

cd "$(git rev-parse --show-toplevel)"

echo "→ build"
pnpm -r build

echo "→ typecheck"
pnpm -r typecheck

echo "→ test"
pnpm -r test

echo "→ lint"
pnpm lint

# Marker for Claude Code's .claude/hooks/{commit-gate,validate-gate}.sh —
# its presence (+ mtime newer than any .ts/.tsx edited this session) lets
# Claude `git commit`/`git push` and declare turns done. See those hooks
# for the freshness logic.
touch /tmp/released-validate.stamp
